def parse_cbc_results(cbc_details):
    '''
    Parses CBC lab test details, compares values with reference ranges, and returns a structured report.
    :param cbc_details: Dict containing CBC parameters, their values, units, and reference ranges.
    :return: List of dicts with fields: parameter, value, unit, reference range, and flag ('Low', 'Normal', 'High').
    '''
    results = []
    for param, details in cbc_details.items():
        value = details.get("value")
        unit = details.get("unit", "")
        ref_range = details.get("ref_range", "")
        flag = "Normal"
        # Try to parse reference range (supports formats like "13-17", "20-40", "1-6")
        if value is not None and ref_range and "-" in ref_range:
            try:
                val = float(value.replace(",", "")) if value.replace(".", "", 1).replace(",", "").isdigit() else None
                ref_low, ref_high = [float(x) for x in ref_range.strip().split("-")]
                if val is not None:
                    if val < ref_low:
                        flag = "Low"
                    elif val > ref_high:
                        flag = "High"
            except Exception:
                flag = "Unknown"
        results.append({
            "parameter": param,
            "value": value,
            "unit": unit,
            "reference_range": ref_range,
            "flag": flag
        })
    return results
